import axios from 'axios';

const apiBaseUrl = process.env.REACT_APP_API_URL || 'http://localhost:8000/api';

const api = axios.create({
  baseURL: apiBaseUrl,
  timeout: 10000,
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('fintrack_token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const getApiErrorMessage = (error) => {
  if (error.response?.data?.message) {
    return error.response.data.message;
  }

  if (error.code === 'ECONNABORTED') {
    return 'The FinTrack API timed out. Check whether the backend is running.';
  }

  if (!error.response) {
    return `Cannot reach the FinTrack API at ${apiBaseUrl}. Start the backend on port 8000.`;
  }

  return 'The request could not be completed. Please try again.';
};

export default api;
